(function() {
  const SELECTOR = ".target-button"; // Change to your target selector
  const INTERVAL_MS = 3000; // Change interval in milliseconds

  // Stop any previously running auto-clicker
  if (window.__browserAutomataAutoClicker) {
    clearInterval(window.__browserAutomataAutoClicker);
    window.__browserAutomataAutoClicker = undefined;
    console.log('[Auto-Clicker] Stopped previous instance.');
    return;
  }

  const intervalId = setInterval(function() {
    const el = document.querySelector(SELECTOR);
    if (el instanceof HTMLElement) {
      el.click();
    }
  }, INTERVAL_MS);

  window.__browserAutomataAutoClicker = intervalId;
  console.log('[Auto-Clicker] Started — clicking "' + SELECTOR + '" every ' + INTERVAL_MS + 'ms. Run again to stop.');
})();
